                    "out = \"out\"\n"
                    "libs = []\n"
                )
                if bin_:
                    foundry_toml += f"solc = \"{bin_}\"\n"

                evm_version = settings.get("evmVersion")
                if evm_version:
                    foundry_toml += f"evm_version = \"{evm_version}\"\n"

                (temp_dir / "foundry.toml").write_text(foundry_toml, encoding="utf-8")

                # Run Slither on the project root "." inside temp_dir
                cmd = ["slither", ".", "--json", "-"]
                if bin_:
                    cmd += ["--solc", str(bin_)]

